import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  listRequestsForMentor,
  listProjectsForMentor,
  listAvailabilityForMentor,
  createAvailability,
  updateMentorRequest,
} from "../api/resources";
import { getUserId } from "../api/users";
import logout from "../utils/logout";
import "./mentorDashboard.css";

export default function MentorDashboard() {
  const navigate = useNavigate();
  const mentorId = getUserId();

  const [activeTab, setActiveTab] = useState("requests");
  const [requests, setRequests] = useState([]);
  const [projects, setProjects] = useState([]);
  const [slots, setSlots] = useState([]);
  const [newSlot, setNewSlot] = useState({
    day: "",
    start_time: "",
    end_time: "",
    location: "",
  });

  useEffect(() => {
    if (!mentorId) {
      navigate("/login");
      return;
    }
    const load = async () => {
      try {
        const [reqRes, projRes, slotRes] = await Promise.all([
          listRequestsForMentor(mentorId),
          listProjectsForMentor(mentorId),
          listAvailabilityForMentor(mentorId),
        ]);
        setRequests(reqRes.data || []);
        setProjects(projRes.data || []);
        setSlots(slotRes.data || []);
      } catch (err) {
        console.error(err);
      }
    };
    load();
  }, [mentorId, navigate]);

  const handleAccept = async (r) => {
    await updateMentorRequest(r.id, { status: "accepted" });
    const res = await listRequestsForMentor(mentorId);
    setRequests(res.data || []);
  };

  const handleReject = async (r) => {
    await updateMentorRequest(r.id, { status: "rejected" });
    const res = await listRequestsForMentor(mentorId);
    setRequests(res.data || []);
  };

  const handleAddSlot = async () => {
    const { day, start_time, end_time, location } = newSlot;
    if (!day || !start_time || !end_time) return alert("Fill all fields");
    await createAvailability({
      mentor_id: mentorId,
      day,
      start_time,
      end_time,
      location,
    });
    const slotRes = await listAvailabilityForMentor(mentorId);
    setSlots(slotRes.data || []);
    setNewSlot({ day: "", start_time: "", end_time: "", location: "" });
  };

  return (
    <div className="mentor-dashboard">
      <div className="header">
        <h2>Mentor Dashboard</h2>
        <button onClick={() => logout(navigate)}>Logout</button>
      </div>

      <div className="tabs">
        {["requests", "projects", "availability"].map((tab) => (
          <button
            key={tab}
            className={activeTab === tab ? "active" : ""}
            onClick={() => setActiveTab(tab)}
          >
            {tab.toUpperCase()}
          </button>
        ))}
      </div>

      <div className="content">
        {activeTab === "requests" && (
          <div>
            <h3>Mentor Requests</h3>
            {requests.length === 0 ? (
              <p>No requests yet.</p>
            ) : (
              requests.map((r) => (
                <div key={r.id} className="card">
                  <p>
                    <b>{r.project_title}</b> by {r.student_name} (
                    {r.student_email})
                  </p>
                  <p>Status: {r.status}</p>
                  {r.status === "pending" && (
                    <>
                      <button onClick={() => handleAccept(r)}>Accept</button>
                      <button onClick={() => handleReject(r)}>Reject</button>
                    </>
                  )}
                </div>
              ))
            )}
          </div>
        )}

        {activeTab === "projects" && (
          <div>
            <h3>Approved Projects</h3>
            {projects.length === 0 ? (
              <p>No projects yet.</p>
            ) : (
              projects.map((p) => (
                <div key={p.id} className="card">
                  <h4>{p.title}</h4>
                  <p>{p.description}</p>
                </div>
              ))
            )}
          </div>
        )}

        {activeTab === "availability" && (
          <div>
            <h3>Availability</h3>
            <div className="form">
              <input
                type="date"
                value={newSlot.day}
                onChange={(e) =>
                  setNewSlot({ ...newSlot, day: e.target.value })
                }
              />
              <input
                type="time"
                value={newSlot.start_time}
                onChange={(e) =>
                  setNewSlot({ ...newSlot, start_time: e.target.value })
                }
              />
              <input
                type="time"
                value={newSlot.end_time}
                onChange={(e) =>
                  setNewSlot({ ...newSlot, end_time: e.target.value })
                }
              />
              <input
                type="text"
                placeholder="Location"
                value={newSlot.location}
                onChange={(e) =>
                  setNewSlot({ ...newSlot, location: e.target.value })
                }
              />
              <button onClick={handleAddSlot}>Add Slot</button>
            </div>

            <div className="slots">
              {slots.length === 0 ? (
                <p>No slots added.</p>
              ) : (
                slots.map((slot) => (
                  <div key={slot.id} className="slot">
                    <p>
                      {slot.day} — {slot.start_time}-{slot.end_time}
                    </p>
                    <p>{slot.location}</p>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
